// error-handling.js - 完整的错误处理和日志诊断示例

const fs = require('fs').promises;
const path = require('path');

// 自定义错误类
class AppError extends Error {
  constructor(message, statusCode, errorCode) {
    super(message);
    this.statusCode = statusCode;
    this.errorCode = errorCode;
    this.isOperational = true;
    Error.captureStackTrace(this, this.constructor);
  }
}

class ValidationError extends AppError {
  constructor(field, message) {
    super(message, 400, 'VALIDATION_ERROR');
    this.field = field;
  }
}

class NotFoundError extends AppError {
  constructor(resource) {
    super(`${resource} 未找到`, 404, 'NOT_FOUND');
    this.resource = resource;
  }
}

// 错误日志记录器
class ErrorLogger {
  constructor() {
    this.errors = [];
    this.maxErrors = 100;
  }

  log(error, context = {}) {
    const errorEntry = {
      timestamp: new Date().toISOString(),
      message: error.message,
      stack: error.stack,
      statusCode: error.statusCode,
      errorCode: error.errorCode,
      context,
      userAgent: context.userAgent || 'unknown'
    };

    this.errors.push(errorEntry);

    // 保持日志数量在限制内
    if (this.errors.length > this.maxErrors) {
      this.errors.shift();
    }

    // 输出到控制台（生产环境应写入文件）
    console.error(`[${errorEntry.timestamp}] ${error.errorCode}: ${error.message}`);

    return errorEntry;
  }

  getRecentErrors(count = 10) {
    return this.errors.slice(-count);
  }

  getErrorsByCode(errorCode) {
    return this.errors.filter(e => e.errorCode === errorCode);
  }

  generateReport() {
    const errorCounts = {};
    this.errors.forEach(e => {
      errorCounts[e.errorCode] = (errorCounts[e.errorCode] || 0) + 1;
    });

    return {
      totalErrors: this.errors.length,
      errorCounts,
      recentErrors: this.getRecentErrors(5)
    };
  }
}

// 使用示例
async function processUserFile(userId) {
  const logger = new ErrorLogger();

  try {
    // 验证输入
    if (!userId || typeof userId !== 'string') {
      throw new ValidationError('userId', 'userId 必须是有效的字符串');
    }

    // 读取用户文件
    const filePath = path.join(__dirname, 'data', `${userId}.json`);
    const content = await fs.readFile(filePath, 'utf-8');

    // 解析 JSON
    const userData = JSON.parse(content);

    // 验证数据
    if (!userData.name) {
      throw new ValidationError('name', '用户数据缺少 name 字段');
    }

    return userData;

  } catch (error) {
    // 使用日志记录错误
    logger.log(error, { userId, operation: 'processUserFile' });

    // 根据错误类型重新抛出
    if (error.code === 'ENOENT') {
      throw new NotFoundError(`用户文件: ${userId}`);
    }

    throw error;
  }
}

// 测试错误处理
async function testErrors() {
  const logger = new ErrorLogger();

  console.log('=== 测试错误处理 ===\n');

  // 测试 1: 验证错误
  try {
    await processUserFile(123);  // 传入数字而非字符串
  } catch (error) {
    logger.log(error, { testCase: 'invalid_type' });
    console.log(`✓ 捕获到验证错误: ${error.message}\n`);
  }

  // 测试 2: 文件不存在
  try {
    await processUserFile('nonexistent_user');
  } catch (error) {
    logger.log(error, { testCase: 'file_not_found' });
    console.log(`✓ 捕获到文件未找到错误: ${error.message}\n`);
  }

  // 输出错误报告
  console.log('=== 错误报告 ===');
  console.log(JSON.stringify(logger.generateReport(), null, 2));
}

// 运行测试
testErrors();


