// 目标：计算每个用户的平均分，并过滤掉平均分低于80的用户

function processUsers(userList) {
  // 第一步：断点 - 验证输入
  console.log('Step 1 - 输入数据:', userList.length, '个用户');

  // 第二步：断点 - 过滤逻辑
  const filtered = userList.filter(user => {
    // 断点：检查每个用户
    console.log(`检查用户 ${user.name}:`, user.scores);
    return user.scores.length > 0; // 过滤掉没有分数的用户
  });
  console.log('Step 2 - 过滤后:', filtered.length, '个用户');

  // 第三步：断点 - 计算平均分
  const withAverages = filtered.map(user => {
    const sum = user.scores.reduce((a, b) => a + b, 0);
    const avg = sum / user.scores.length; // 这里有问题！
    console.log(`${user.name} - 总分: ${sum}, 数量: ${user.scores.length}, 平均: ${avg}`);
    return { ...user, average: avg };
  });
  console.log('Step 3 - 计算平均分完成');

  // 第四步：断点 - 最终过滤
  const result = withAverages.filter(user => {
    console.log(`最终检查 ${user.name}: 平均分 ${user.average}`);
    return user.average >= 80;
  });

  console.log('Step 4 - 最终结果:', result);
  return result;
}

