// 示例 3：API 集成的错误处理模式

const axios = require('axios');

class ApiClient {
  constructor(baseURL, apiKey) {
    this.client = axios.create({
      baseURL,
      timeout: 10000,
      headers: {
        'Authorization': `Bearer ${apiKey}`,
        'Content-Type': 'application/json'
      }
    });

    // 添加拦截器处理错误
    this.setupInterceptors();
  }

  setupInterceptors() {
    // 响应拦截器
    this.client.interceptors.response.use(
      response => response,
      error => {
        const { response, message, code } = error;

        // 常见错误分类
        if (response) {
          switch (response.status) {
            case 400:
              console.error('❌ 请求参数错误:', response.data);
              break;
            case 401:
              console.error('❌ 认证失败，请检查 API Key');
              break;
            case 403:
              console.error('❌ 权限不足');
              break;
            case 404:
              console.error('❌ 资源不存在');
              break;
            case 429:
              console.error('⚠️ 请求频率超限，等待重试...');
              break;
            case 500:
              console.error('❌ 服务器内部错误');
              break;
            default:
              console.error(`❌ 请求失败: ${response.status}`);
          }
        } else if (code === 'ECONNABORTED') {
          console.error('❌ 请求超时');
        } else {
          console.error('❌ 网络错误:', message);
        }

        return Promise.reject(error);
      }
    );
  }

  // 带重试机制的请求
  async requestWithRetry(config, maxRetries = 3) {
    let lastError;

    for (let i = 0; i < maxRetries; i++) {
      try {
        return await this.client(config);
      } catch (error) {
        lastError = error;

        // 只有在服务器错误或网络错误时重试
        const shouldRetry = 
          !error.response || 
          error.response.status >= 500 ||
          error.code === 'ECONNABORTED';

        if (shouldRetry && i < maxRetries - 1) {
          const delay = Math.pow(2, i) * 1000; // 指数退避
          console.log(`⏳ ${delay/1000}秒后重试 (${i + 1}/${maxRetries})...`);
          await new Promise(resolve => setTimeout(resolve, delay));
        }
      }
    }

    throw lastError;
  }
}

// 使用示例
const api = new ApiClient('https://api.example.com', 'your-api-key');

async function fetchData() {
  try {
    const response = await api.requestWithRetry({
      method: 'GET',
      url: '/users/123'
    });
    console.log('✅ 获取数据成功:', response.data);
    return response.data;
  } catch (error) {
    console.error('💥 最终失败:', error.message);
    throw error;
  }
}

