      [id]
    );
    return results[0] || null;
  }

  async findByEmail(email: string): Promise<User | null> {
    const results = await this.db.query<User>(
      'SELECT * FROM users WHERE email = $1',
      [email]
    );
    return results[0] || null;
  }

  async create(user: Omit<User, 'id' | 'createdAt'>): Promise<User> {
    const id = crypto.randomUUID();
    const createdAt = new Date().toISOString();

    await this.db.execute(
      'INSERT INTO users (id, name, email, created_at) VALUES ($1, $2, $3, $4)',
      [id, user.name, user.email, createdAt]
    );

    return { id, ...user, createdAt: new Date(createdAt) };
  }

  async update(id: string, data: Partial<User>): Promise<User> {
    const fields: string[] = [];
    const values: any[] = [];
    let paramIndex = 1;

    if (data.name !== undefined) {
      fields.push(`name = $${paramIndex++}`);
      values.push(data.name);
    }
    if (data.email !== undefined) {
      fields.push(`email = $${paramIndex++}`);
      values.push(data.email);
    }

    values.push(id);

    await this.db.execute(
      `UPDATE users SET ${fields.join(', ')} WHERE id = $${paramIndex}`,
      values
    );

    const updated = await this.findById(id);
    if (!updated) throw new Error('Update failed');
    return updated;
  }

  async delete(id: string): Promise<void> {
    await this.db.execute(
      'DELETE FROM users WHERE id = $1',
      [id]
    );
  }
}


---

## 四、常见问题与注意事项

### 4.1 常见错误

| 错误类型 | 具体表现 | 后果 |
|---------|---------|------|
| **循环依赖** | A 导入 B，B 导入 A | 模块加载失败，运行错误 |
| **修改遗漏** | 只改了接口忘记改实现 | 编译失败或运行时异常 |
| **类型不一致** | 相邻文件使用不同的类型定义 | 类型检查失败 |
| **职责混淆** | 业务逻辑写在控制层 | 代码难以测试和复用 |
| **过度耦合** | 一个文件依赖太多其他文件 | 难以维护和测试 |

### 4.2 注意事项


1. **保持单向依赖**：层级之间的依赖应该总是向下的，业务逻辑不应该依赖具体的 API 实现

2. **接口隔离原则**：定义清晰的接口边界，不要让一个接口承担太多职责

3. **关注依赖方向**：当发现循环依赖时，需要重新审视模块的划分

### 4.3 架构腐化的预警信号

- 某个文件变得越来越大（超过 500 行）
- 修改一个功能需要同时修改很多文件
- 无法单独运行或测试某个模块
- 类型定义分散在多个文件中且不一致

---

## 五、实践建议

### 5.1 项目结构规划

在开始一个新项目时，首先规划文件结构：


project/
├── src/
│   ├── types/           # 核心类型定义（最先定义）
│   ├── database/        # 数据库抽象和配置
│   ├── repositories/    # 数据访问层（实现 types 中定义的接口）
│   ├── services/        # 业务逻辑层（依赖 repositories）
│   ├── api/             # API 路由层（依赖 services）
│   └── utils/           # 工具函数
├── tests/
└── docs/


### 5.2 与 Claude Code 协作的技巧

1. **提供上下文信息**：
   - 告诉 Claude Code 你使用的框架和架构模式
   - 说明项目的组织方式

2. **指定修改范围**：
   - 如果只需要修改某几个文件，明确指定
   - 如果需要全局修改，说明影响范围

3. **验证修改结果**：
   - 让 Claude Code 解释将要做什么
   - 确认后再执行修改

### 5.3 架构决策清单

在做架构决策时，考虑以下问题：


- [ ] 这个决策会影响多少个文件？
- [ ] 新增的模块与现有模块的关系是什么？
- [ ] 这个设计模式是否与项目风格一致？
- [ ] 未来可能的扩展方向是什么？
- [ ] 这个决策的可逆性如何？

### 5.4 推荐的架构模式

对于大多数中级项目，推荐使用以下模式组合：

- **分层架构**：types → repositories → services → api
- **依赖注入**：通过构造函数或容器注入依赖
- **接口抽象**：用接口定义模块边界
- **工厂模式**：创建复杂对象的统一入口

---

## 总结

多文件协同和架构决策是 Claude Code 实战中的重要能力。通过：

1. **清晰的项目结构**：让 Claude Code 能够快速理解代码组织
2. **明确的接口定义**：建立模块之间的契约
3. **单向的依赖关系**：避免循环依赖和过度耦合
4. **适度的抽象层次**：平衡灵活性和复杂度

你可以在保持代码可维护性的同时，充分发挥 Claude Code 在复杂项目中的辅助作用。


