### 示例 1

```python
/*
 * 示例：多文件项目的依赖管理演示
 * 
 * 场景：需要在多个文件中保持类型一致性
 * 当修改 types/index.ts 中的接口时，所有引用该接口的文件都会同步更新
 */

// 文件：src/types/user.ts
// 核心类型定义，所有模块共享

export interface UserProfile {
  id: string;
  username: string;
  avatar?: string;
  role: 'admin' | 'user' | 'guest';
  preferences: UserPreferences;
}

export interface UserPreferences {
  theme: 'light' | 'dark';
  language: string;
  notifications: boolean;
}

// 文件：src/services/UserPreferencesService.ts
// 业务逻辑层，处理用户偏好设置
import { UserProfile, UserPreferences } from '../types/user';

export class UserPreferencesService {
  // 更新用户偏好设置
  updatePreferences(
    user: UserProfile,
    newPrefs: Partial<UserPreferences>
  ): UserProfile {
    return {
      ...user,
      preferences: {
        ...user.preferences,
        ...newPrefs
      }
    };
  }

  // 验证偏好设置的合法性
  validatePreferences(prefs: UserPreferences): boolean {
    const validThemes = ['light', 'dark'];
    const validLanguages = ['en', 'zh', 'ja', 'es'];

    return (
      validThemes.includes(prefs.theme) &&
      validLanguages.includes(prefs.language) &&
      typeof prefs.notifications === 'boolean'
    );
  }
}

// 使用示例
const user: UserProfile = {
  id: '123',
  username: 'alice',
  role: 'user',
  preferences: {
    theme: 'dark',
    language: 'zh',
    notifications: true
  }
};

const service = new UserPreferencesService();
const updated = service.updatePreferences(user, { theme: 'light' });
console.log('Updated user:', updated);

```

### 示例 2

```python
/*
 * 示例：架构重构 - 从紧耦合到松耦合
 * 
 * 重构前：UserService 直接依赖 InMemoryUserRepository
 * 重构后：通过接口解耦，可以轻松切换存储实现
 */

// === 重构前的代码（紧耦合）===

// 文件：old/UserService.ts
class OldUserService {
  private users: Map<string, any> = new Map();

  getUser(id: string) {
    return this.users.get(id);
  }

  createUser(data: any) {
    const user = { id: Date.now().toString(), ...data };
    this.users.set(user.id, user);
    return user;
  }
  // 问题：存储逻辑和业务逻辑混在一起，难以测试和替换
}


// === 重构后的代码（松耦合）===

// 文件：new/interfaces/UserRepository.ts
// 定义存储层的抽象接口
interface UserRepositoryInterface {
  findById(id: string): Promise<User | null>;
  findAll(): Promise<User[]>;
  save(user: User): Promise<User>;
  delete(id: string): Promise<void>;
}

// 文件：new/types/User.ts
interface User {
  id: string;
  name: string;
  email: string;
}

// 文件：new/repositories/InMemoryUserRepository.ts
// 实现接口，可以被替换
class InMemoryUserRepository implements UserRepositoryInterface {
  private users: Map<string, User> = new Map();

  async findById(id: string): Promise<User | null> {
    return this.users.get(id) || null;
  }

  async findAll(): Promise<User[]> {
    return Array.from(this.users.values());
  }

  async save(user: User): Promise<User> {
    this.users.set(user.id, user);
    return user;
  }

  async delete(id: string): Promise<void> {
    this.users.delete(id);
  }
}

// 文件：new/services/UserService.ts
// 业务逻辑与存储实现解耦
class UserService {
  constructor(private repository: UserRepositoryInterface) {}

  async getUser(id: string): Promise<User> {
    const user = await this.repository.findById(id);
    if (!user) {
      throw new Error(`User ${id} not found`);
    }
    return user;
  }

  async createUser(name: string, email: string): Promise<User> {
    // 业务验证逻辑
    if (!email.includes('@')) {
      throw new Error('Invalid email');
    }

    const user: User = {
      id: crypto.randomUUID(),
      name,
      email
    };

    return this.repository.save(user);
  }
}

// 使用示例
const repository = new InMemoryUserRepository();
const service = new UserService(repository);

service.createUser('Alice', 'alice@example.com')
  .then(user => console.log('Created:', user))
  .catch(err => console.error('Error:', err));

// 轻松替换存储实现
// const repository = new PostgresUserRepository(connectionString);
// const service = new UserService(repository);

```



## 常见错误

- 循环依赖：让两个或多个模块相互导入，形成循环引用，导致运行时错误或构建失败
- 修改遗漏：在重构时只更新了接口定义，但忘记同步修改实现类，导致类型不匹配
- 职责混淆：将业务逻辑、验证逻辑和数据访问逻辑混在一个文件中，使代码难以测试和维护
- 过度抽象：为了追求设计模式的完美而过度抽象，引入了不必要的复杂性
- 忽视类型一致性：在不同文件中使用不同版本的类型定义，导致类型检查失败
- 忽略依赖方向：违反了分层架构的单向依赖原则，让底层模块依赖上层模块
- 单文件修改：在需要跨文件修改时，只修改了其中一个文件，破坏了系统的一致性


## 最佳实践

- 规划清晰的项目结构：在项目初期就建立合理的文件夹结构和模块划分，为后续增长预留空间
- 使用接口定义模块边界：通过 TypeScript 接口或抽象类定义模块之间的契约，便于后续替换实现
- 遵循单向依赖原则：高层模块（如 services）依赖低层模块（如 repositories），反向依赖应该通过依赖注入实现
- 保持类型定义集中：将共享的类型定义放在统一的位置（如 types/index.ts），避免类型分散在多个文件
- 小而专注的模块：每个模块的职责应该单一，文件行数建议控制在 200-300 行以内，超过时考虑拆分
- 编写模块级别的测试：在修改跨文件代码时，先编写测试验证各模块的独立行为，再验证集成行为
- 使用版本控制和分支：在进行架构调整时，使用 Git 分支管理，便于回滚和代码审查
- 渐进式重构：不要试图一次性完成大型架构重构，每次只重构一个模块，确保修改可控

