# Python示例：数据清洗和转换
import pandas as pd
from typing import List, Dict, Optional
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

def clean_and_transform_data(
    raw_data: List[Dict],
    required_fields: List[str],
    field_mappings: Optional[Dict[str, str]] = None
) -> pd.DataFrame:
    """
    清洗和转换原始数据

    Args:
        raw_data: 原始数据列表
        required_fields: 必需字段列表
        field_mappings: 字段映射字典 {'原字段名': '新字段名'}

    Returns:
        清洗后的DataFrame
    """
    if not raw_data:
        logger.warning("输入数据为空")
        return pd.DataFrame()

    df = pd.DataFrame(raw_data)

    # 检查必需字段
    missing_fields = set(required_fields) - set(df.columns)
    if missing_fields:
        logger.error(f"缺少必需字段: {missing_fields}")
        raise ValueError(f"数据缺少必需字段: {missing_fields}")

    # 应用字段映射
    if field_mappings:
        df = df.rename(columns=field_mappings)

    # 数据类型转换
    numeric_columns = ['price', 'quantity', 'amount']
    for col in numeric_columns:
        if col in df.columns:
            df[col] = pd.to_numeric(df[col], errors='coerce')

    # 去除重复
    original_len = len(df)
    df = df.drop_duplicates()
    if len(df) < original_len:
        logger.info(f"移除了 {original_len - len(df)} 条重复记录")

    # 处理缺失值
    df = df.fillna({
        'price': 0,
        'quantity': 0,
        'status': 'unknown'
    })

    # 添加元数据
    df['processed_at'] = pd.Timestamp.now()

    logger.info(f"数据处理完成: {len(df)} 条记录")
    return df
// TypeScript示例：HTTP客户端封装
interface ApiConfig {
  baseUrl: string;
  timeout?: number;
  headers?: Record<string, string>;
}

interface RequestOptions {
  method: 'GET' | 'POST' | 'PUT' | 'DELETE';
  path: string;
  params?: Record<string, string>;
  body?: unknown;
}

class ApiClient {
  private config: ApiConfig;

  constructor(config: ApiConfig) {
    this.config = {
      timeout: 30000,
      ...config
    };
  }

  private async request<T>(options: RequestOptions): Promise<T> {
    const controller = new AbortController();
    const timeoutId = setTimeout(
      () => controller.abort(),
      this.config.timeout
    );

    try {
      // 构建URL
      const url = new URL(options.path, this.config.baseUrl);
      if (options.params) {
        Object.entries(options.params).forEach(([key, value]) => {
          url.searchParams.append(key, value);
        });
      }

      // 发送请求
      const response = await fetch(url.toString(), {
        method: options.method,
        headers: {
          'Content-Type': 'application/json',
          ...this.config.headers,
        },
        body: options.body ? JSON.stringify(options.body) : undefined,
        signal: controller.signal,
      });

      // 处理HTTP错误
      if (!response.ok) {
        const errorBody = await response.text();
        throw new ApiError(
          response.status,
          response.statusText,
          errorBody
        );
      }

      return await response.json() as T;
    } finally {
      clearTimeout(timeoutId);
    }
  }

  // 便捷方法
  async get<T>(path: string, params?: Record<string, string>): Promise<T> {
    return this.request<T>({ method: 'GET', path, params });
  }

  async post<T>(path: string, body: unknown): Promise<T> {
    return this.request<T>({ method: 'POST', path, body });
  }

  async put<T>(path: string, body: unknown): Promise<T> {
    return this.request<T>({ method: 'PUT', path, body });
  }

  async delete<T>(path: string): Promise<T> {
    return this.request<T>({ method: 'DELETE', path });
  }
}

class ApiError extends Error {
  constructor(
    public status: number,
    public statusText: string,
    public body: string
  ) {
    super(`API Error: ${status} ${statusText}`);
    this.name = 'ApiError';
  }
}

// 使用示例
const api = new ApiClient({
  baseUrl: 'https://api.example.com/v1',
  timeout: 15000
});

interface User {
  id: string;
  name: string;
  email: string;
}

// 获取用户列表
const users = await api.get<User[]>('/users', { page: '1', limit: '10' });
console.log(`获取到 ${users.length} 个用户`);

