/edit src/utils/calculator.js
将 calculate 函数修改为支持加法、减法、乘法和除法，
需要处理除数为零的错误情况。

// 修改后的代码
function calculate(a, operator, b) {
  switch (operator) {
    case '+':
      return a + b;
    case '-':
      return a - b;
    case '*':
      return a * b;
    case '/':
      if (b === 0) {
        throw new Error('除数不能为零');
      }
      return a / b;
    default:
      throw new Error('不支持的运算符');
  }
}

