// 重构后的代码
const filterActiveItems = (data) => data.filter(item => item.active);

const transformItems = (data, options) => 
  data.map(item => transform(item, options));

const sumValues = (data) => 
  data.reduce((sum, item) => sum + item.value, 0);

function processData(data, options) {
  return data
    |> filterActiveItems
    |> (items) => transformItems(items, options)
    |> sumValues;
}

