### 示例 3

```python
// 示例3：使用 Claude Code 进行渐进式重构并验证
// 场景：重构一个计算商品折扣的模块

// 重构前：折扣计算逻辑混乱
function calculateDiscount(product, user, orderDate) {
    let discount = 0;

    // 会员折扣
    if (user.memberLevel === 'gold') {
        discount = product.price * 0.2;
    } else if (user.memberLevel === 'silver') {
        discount = product.price * 0.1;
    }

    // 节日折扣
    const holidays = ['2024-01-01', '2024-12-25', '2024-11-11'];
    if (holidays.includes(orderDate.split('T')[0])) {
        discount += product.price * 0.05;
    }

    // 限时折扣
    if (product.flashSale && new Date() < new Date(product.flashSaleEnd)) {
        discount += product.price * 0.15;
    }

    // 满减折扣
    if (product.price > 100) {
        discount += 10;
    } else if (product.price > 200) {
        discount += 20;
    }

    // 最高折扣限制
    if (discount > product.price * 0.5) {
        discount = product.price * 0.5;
    }

    return discount;
}

// 使用 Claude Code 重构后的清晰版本
class DiscountCalculator {
    constructor(product, user, orderDate) {
        this.product = product;
        this.user = user;
        this.orderDate = new Date(orderDate);
        this.discounts = [];
    }

    calculate() {
        this.applyMemberDiscount();
        this.applyHolidayDiscount();
        this.applyFlashSaleDiscount();
        this.applyThresholdDiscount();
        return this.getFinalDiscount();
    }

    applyMemberDiscount() {
        const memberDiscounts = {
            'gold': 0.2,
            'silver': 0.1,
            'bronze': 0.05
        };
        const rate = memberDiscounts[this.user.memberLevel] || 0;
        this.discounts.push({ type: 'member', rate });
    }

    applyHolidayDiscount() {
        const holidays = [
            new Date('2024-01-01'),
            new Date('2024-12-25'),
            new Date('2024-11-11')
        ];
        if (holidays.some(h => h.toDateString() === this.orderDate.toDateString())) {
            this.discounts.push({ type: 'holiday', rate: 0.05 });
        }
    }

    applyFlashSaleDiscount() {
        if (this.product.flashSale && new Date() < new Date(this.product.flashSaleEnd)) {
            this.discounts.push({ type: 'flashSale', rate: 0.15 });
        }
    }

    applyThresholdDiscount() {
        const thresholds = [
            { minPrice: 200, amount: 20 },
            { minPrice: 100, amount: 10 }
        ];
        const threshold = thresholds.find(t => this.product.price >= t.minPrice);
        if (threshold) {
            this.discounts.push({ type: 'threshold', amount: threshold.amount });
        }
    }

    getFinalDiscount() {
        // 计算折扣总额
        const percentageDiscount = this.discounts
            .filter(d => d.rate !== undefined)
            .reduce((sum, d) => sum + this.product.price * d.rate, 0);

        const fixedDiscount = this.discounts
            .filter(d => d.amount !== undefined)
            .reduce((sum, d) => sum + d.amount, 0);

        let totalDiscount = percentageDiscount + fixedDiscount;

        // 应用最高折扣限制
        const maxDiscount = this.product.price * 0.5;
        return Math.min(totalDiscount, maxDiscount);
    }
}

// 使用示例
const calculator = new DiscountCalculator(
    { price: 150, flashSale: true, flashSaleEnd: '2025-12-31' },
    { memberLevel: 'gold' },
    '2024-11-11'
);
console.log(`折扣金额: ¥${calculator.calculate().toFixed(2)}`);
```



## 常见错误

- 在重构的同时添加新功能，导致无法区分是重构引入的问题还是新功能的问题
- 一次性进行大幅度重构，导致问题排查困难，应该小步快跑，每次只改一点
- 重构前没有备份或没有提交到版本控制系统，出了问题无法回滚
- 忽视测试的重要性，没有测试覆盖的重构是危险的
- 过度优化，为了追求完美的代码而花费过多时间，忽略了实际收益
- 忽略边界情况，重构后对异常输入的处理可能不完整
- 在重构过程中改变函数或类的接口，导致调用方出现兼容性问题
- 没有为重构后的代码添加相应的注释和文档，增加了维护难度


## 最佳实践

- 每次重构前先运行现有测试，确保基线正常；重构后立即再次运行测试验证
- 使用版本控制系统，每次小重构后提交，描述清楚改了什么和为什么改
- 遵循"童子军规则"：每次离开时，让代码比来时更干净一点
- 明确区分重构和重写，只有当代码真的无法维护时才考虑重写
- 使用 Claude Code 的 /review 命令先分析代码结构，识别重构优先级
- 创建重构清单，先处理高优先级的问题（如影响核心功能的Bug）
- 对于复杂重构，先在本地分支进行，充分验证后再合并到主分支
- 记录重构决策和结果，便于后续回顾和团队知识共享
- 保持重构的原子性，每个提交只包含一个逻辑变更
- 定期进行代码审查，让团队成员互相监督代码质量

