### 示例 2：Python 日志分析与诊断

python
import logging
import json
from typing import List, Dict, Any

# 配置日志格式
logging.basicConfig(
    level=logging.DEBUG,
    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s'
)
logger = logging.getLogger(__name__)

class DataProcessor:
    """数据处理器类 - 演示日志诊断"""

    def __init__(self):
        self.processed_count = 0
        self.error_count = 0
        self.errors = []

    def process_items(self, items: List[Dict[str, Any]]) -> List[Dict]:
        """
        处理数据项，记录详细日志

        Args:
            items: 待处理的数据列表

        Returns:
            处理后的数据列表
        """
        results = []

        for index, item in enumerate(items):
            try:
                logger.debug(f"处理第 {index + 1} 项: {json.dumps(item, ensure_ascii=False)}")

                # 模拟可能出错的操作
                processed_item = self._process_single_item(item)
                results.append(processed_item)

                self.processed_count += 1
                logger.info(f"成功处理第 {index + 1} 项")

            except ValueError as e:
                self.error_count += 1
                error_info = {
                    'index': index,
                    'item': item,
                    'error': str(e)
                }
                self.errors.append(error_info)
                logger.warning(f"数据验证失败 (第 {index + 1} 项): {e}")

            except Exception as e:
                self.error_count += 1
                error_info = {
                    'index': index,
                    'item': item,
                    'error': str(e),
                    'type': type(e).__name__
                }
                self.errors.append(error_info)
                logger.error(f"处理失败 (第 {index + 1} 项): {type(e).__name__} - {e}")

        return results

    def _process_single_item(self, item: Dict[str, Any]) -> Dict:
        """处理单个数据项"""
        # 数据验证
        if 'name' not in item:
            raise ValueError("缺少必需字段: name")

        if 'price' in item and item['price'] < 0:
            raise ValueError(f"价格不能为负数: {item['price']}")

        # 处理逻辑
        return {
            'id': item.get('id', 'unknown'),
            'name': item['name'].strip().upper(),
            'price': item.get('price', 0),
            'category': item.get('category', 'uncategorized').lower()
        }

    def get_error_summary(self) -> Dict:
        """获取错误摘要"""
        return {
            'total_processed': self.processed_count,
            'total_errors': self.error_count,
            'error_rate': f"{(self.error_count / (self.processed_count + self.error_count) * 100):.2f}%",
            'errors': self.errors
        }


# 测试代码
if __name__ == "__main__":
    test_data = [
        {'id': 1, 'name': '  产品 A  ', 'price': 99.9, 'category': 'Electronics'},
        {'id': 2, 'name': '产品 B', 'price': -10},  # 价格错误
        {'id': 3},  # 缺少 name
        {'id': 4, 'name': '产品 D', 'price': 50},
    ]

    processor = DataProcessor()
    results = processor.process_items(test_data)

    # 输出结果
    print("\n" + "=" * 50)
    print("处理结果:", results)
    print("\n错误摘要:", json.dumps(processor.get_error_summary(), indent=2, ensure_ascii=False))


