    return { success: true, token: this.token };
  }

  // 获取用户信息
  async getUserInfo() {
    console.log('📋 获取用户信息...');
    // 断点 2：验证依赖
    if (!this.token) {
      throw new Error('未登录，无法获取用户信息');
    }

    await this.delay(500);

    this.userInfo = {
