```python
/* 示例2：使用 Claude Code 辅助调试异步调用链
 * 场景：模拟用户登录后获取信息的完整流程
 * 运行方式：node debug_example2.js
 * Claude 调试提示：Claude 可以帮助分析异步调用链的问题
 */

class UserService {
  constructor() {
    this.token = null;
    this.userInfo = null;
  }

  async login(username, password) {
    console.log('🔐 登录中...');
    if (!username || !password) {
      throw new Error('用户名和密码不能为空');
    }
    await this.delay(500);
    this.token = 'token_' + Date.now();
    console.log('✅ 登录成功, token:', this.token);
    return { success: true, token: this.token };
  }

  async getUserInfo() {
    console.log('📋 获取用户信息...');
    // 断点：验证依赖状态
    if (!this.token) {
      throw new Error('❌ 错误：未登录，无法获取用户信息');
    }
    await this.delay(300);
    this.userInfo = { id: 1, name: '测试用户' };
    console.log('✅ 用户信息:', this.userInfo);
    return this.userInfo;
  }

  async initSession(username, password) {
    try {
      await this.login(username, password);
      await this.getUserInfo();
      console.log('🎉 初始化完成!');
    } catch (error) {
      console.log('捕获错误:', error.message);
      // Claude 建议：这里应该提供更详细的错误上下文
      throw new Error(`初始化失败: ${error.message}`);
    }
  }

  delay(ms) {
    return new Promise(resolve => setTimeout(resolve, ms));
  }
}

// 测试场景
async function test() {
  console.log('=== 正常流程测试 ===');
  const service = new UserService();
  await service.initSession('admin', '123');

  console.log('\n=== 错误流程：跳过登录 ===');
  const service2 = new UserService();
  try {
    await service2.getUserInfo(); // 未登录直接调用
  } catch (e) {
    console.log('预期错误:', e.message);
    /* Claude 分析：
     * 1. this.token 为 undefined
     * 2. 检查在构造函数中是否正确初始化
     * 3. 确认调用顺序
     */
  }
}

test();
```



## 常见错误

- 盲目修改代码而不验证假设，导致引入更多 bug
- 在调试时添加大量无意义的日志，导致输出混乱难以分析
- 只关注报错的那一行代码，忽略上游调用链的问题
- 只测试正常路径，忽视边界情况和异常输入
- 过度依赖 Claude 的建议而不自己分析，失去独立思考能力
- 遇到复杂问题时不简化，直接在完整代码中调试
- 修改代码后不记录，导致问题难以复现和回滚
- 在调试中陷入细节，花费过多时间而忘记全局目标
- 认为问题一定是新代码引入的，忽视历史代码的潜在问题
- 不使用版本控制工具比对，错过快速定位的机会


## 最佳实践

- 使用橡皮鸭调试法：向他人或物品解释问题，往往能在解释过程中发现答案
- 采用二分法定位：将代码或数据对半划分，快速缩小问题范围
- 遵循「最小复现」原则：提取问题的最小可复现代码进行调试
- 在调试前清晰定义问题：用一句话描述问题现象和预期行为
- 使用 Claude Code 时提供完整上下文：包括代码片段、错误信息和已尝试的方法
- 养成记录调试过程的习惯：记录问题现象、根因和解决方法，便于复盘
- 设置调试时间限制：避免在一个问题上花费过多时间
- 主动寻找否定自己假设的证据：防止确认偏误影响判断
- 调试完成后立即写单元测试：确保修复不会引入回归
- 定期复盘调试案例：总结方法论，持续提升调试效率

