  try {
    const outdated = execSync('npm outdated', { encoding: 'utf-8' });
    console.log(outdated);
  } catch {
    console.log('所有包都是最新版本');
  }

  // 3. 检查 peer dependencies
  console.log('\n🔍 Peer Dependencies 检查：');
  try {
    const audit = execSync('npm audit', { encoding: 'utf-8' });
    console.log(audit);
  } catch (error) {
    console.log('发现问题：');
    console.log(error.stdout);
  }
}

// 常见的解决方案
const solutions = {
  // 方案1：清理重新安装
  cleanReinstall: () => {
    console.log('\n🧹 执行清理重新安装...');
    execSync('rm -rf node_modules package-lock.json', { stdio: 'inherit' });
    execSync('npm install', { stdio: 'inherit' });
  },

  // 方案2：使用 legacy peer deps
