        """测试两个负数相加"""
        result = add(-2, -3)
        assert result == -5, "负数相加结果应该正确"

    def test_add_mixed_signs(self):
        """测试一正一负相加"""
        result = add(-5, 3)
        assert result == -2

    # 测试边界情况
    def test_add_zero(self):
        """测试与零相加"""
        result = add(10, 0)
        assert result == 10

    # 测试除法 - 包含异常处理
    def test_divide_normal(self):
        """测试正常除法"""
        result = divide(10, 2)
        assert result == 5

