import pytest
from calculator import add, divide, factorial

class TestCalculator:
    """计算器功能测试类"""

    # 测试正常输入
    def test_add_positive_numbers(self):
        """测试两个正数相加"""
        result = add(3, 5)
        assert result == 8, "正数相加结果应该正确"

    def test_add_negative_numbers(self):
        """测试两个负数相加"""
        result = add(-2, -3)
        assert result == -5, "负数相加结果应该正确"

    def test_add_mixed_signs(self):
        """测试一正一负相加"""
        result = add(-5, 3)
        assert result == -2

    # 测试边界情况
    def test_add_zero(self):
        """测试与零相加"""
        result = add(10, 0)
        assert result == 10

    # 测试除法 - 包含异常处理
    def test_divide_normal(self):
        """测试正常除法"""
        result = divide(10, 2)
        assert result == 5

    def test_divide_by_zero(self):
        """测试除以零的异常处理"""
        with pytest.raises(ValueError, match="除数不能为零"):
            divide(10, 0)

    # 测试阶乘函数
    def test_factorial_normal(self):
        """测试正常阶乘计算"""
        result = factorial(5)
        assert result == 120

    def test_factorial_zero(self):
        """测试 0 的阶乘（边界值）"""
        result = factorial(0)
        assert result == 1, "0! 应该等于 1"

    def test_factorial_negative(self):
        """测试负数输入的异常处理"""
        with pytest.raises(ValueError, match="输入必须为非负整数"):
            factorial(-5)

