import pytest
from bug_reporter import process_user_data

class TestBugFixVerification:
    """验证之前 bug 修复的测试套件"""

    def setup_method(self):
        """每个测试前的准备工作"""
        self.valid_user_data = {
            'name': '张三',
            'age': 25,
            'email': 'zhangsan@example.com'
        }

    # ================== 原 Bug 复现测试 ==================

    def test_fix_email_validation(self):
        """
        验证修复：之前缺少邮箱格式验证
        预期：现在能正确验证无效邮箱
        """
        invalid_data = self.valid_user_data.copy()
        invalid_data['email'] = 'invalid-email'

        with pytest.raises(ValueError, match='邮箱格式不正确'):
            process_user_data(invalid_data)

    def test_fix_age_boundary(self):
        """
        验证修复：之前负数年龄未被处理
        预期：现在能正确拒绝负数年龄
        """
        invalid_data = self.valid_user_data.copy()
        invalid_data['age'] = -5

        with pytest.raises(ValueError, match='年龄必须为非负数'):
            process_user_data(invalid_data)

    def test_fix_name_empty_handling(self):
        """
        验证修复：之前空名字未被过滤
        预期：现在能正确处理空名字情况
        """
        invalid_data = self.valid_user_data.copy()
        invalid_data['name'] = ''

        with pytest.raises(ValueError, match='姓名不能为空'):
            process_user_data(invalid_data)

    # ================== 回归测试 ==================

    def test_regression_valid_data_still_works(self):
        """
        回归测试：确保修复没有破坏正常功能
        """
        result = process_user_data(self.valid_user_data)
        assert result['name'] == '张三'
        assert result['age'] == 25

    def test_regression_boundary_ages(self):
        """
        回归测试：确保边界年龄值仍然有效
        """
        test_cases = [
            {'age': 0, 'should_pass': True},
            {'age': 1, 'should_pass': True},
            {'age': 150, 'should_pass': True},
        ]

        for case in test_cases:
            data = self.valid_user_data.copy()
            data['age'] = case['age']
            if case['should_pass']:
                result = process_user_data(data)
                assert result['age'] == case['age']

    # ================== 集成测试 ==================

    def test_integration_batch_processing(self):
        """
        集成测试：测试批量数据处理
        """
        batch_data = [
            {'name': '用户1', 'age': 20, 'email': 'user1@test.com'},
            {'name': '用户2', 'age': 30, 'email': 'user2@test.com'},
        ]

        from bug_reporter import batch_process_users
        results = batch_process_users(batch_data)

        assert len(results) == 2
        assert all(r['status'] == 'success' for r in results)

