/*
 * 示例：多文件项目的依赖管理演示
 * 
 * 场景：需要在多个文件中保持类型一致性
 * 当修改 types/index.ts 中的接口时，所有引用该接口的文件都会同步更新
 */

// 文件：src/types/user.ts
// 核心类型定义，所有模块共享

export interface UserProfile {
  id: string;
  username: string;
  avatar?: string;
  role: 'admin' | 'user' | 'guest';
  preferences: UserPreferences;
}

export interface UserPreferences {
