    const validLanguages = ['en', 'zh', 'ja', 'es'];

    return (
      validThemes.includes(prefs.theme) &&
      validLanguages.includes(prefs.language) &&
      typeof prefs.notifications === 'boolean'
    );
  }
}

// 使用示例
const user: UserProfile = {
  id: '123',
  username: 'alice',
  role: 'user',
  preferences: {
    theme: 'dark',
    language: 'zh',
    notifications: true
  }
};

const service = new UserPreferencesService();
const updated = service.updatePreferences(user, { theme: 'light' });
console.log('Updated user:', updated);

```

### 示例 2

```python
/*
 * 示例：架构重构 - 从紧耦合到松耦合
 * 
 * 重构前：UserService 直接依赖 InMemoryUserRepository
 * 重构后：通过接口解耦，可以轻松切换存储实现
 */

// === 重构前的代码（紧耦合）===

// 文件：old/UserService.ts
class OldUserService {
  private users: Map<string, any> = new Map();

  getUser(id: string) {
    return this.users.get(id);
  }

  createUser(data: any) {
    const user = { id: Date.now().toString(), ...data };
    this.users.set(user.id, user);
    return user;
  }
  // 问题：存储逻辑和业务逻辑混在一起，难以测试和替换
}


// === 重构后的代码（松耦合）===

// 文件：new/interfaces/UserRepository.ts
// 定义存储层的抽象接口
interface UserRepositoryInterface {
  findById(id: string): Promise<User | null>;
  findAll(): Promise<User[]>;
  save(user: User): Promise<User>;
  delete(id: string): Promise<void>;
}

// 文件：new/types/User.ts
interface User {
  id: string;
  name: string;
  email: string;
}

// 文件：new/repositories/InMemoryUserRepository.ts
// 实现接口，可以被替换
class InMemoryUserRepository implements UserRepositoryInterface {
  private users: Map<string, User> = new Map();

  async findById(id: string): Promise<User | null> {
    return this.users.get(id) || null;
  }

  async findAll(): Promise<User[]> {
    return Array.from(this.users.values());
  }

  async save(user: User): Promise<User> {
    this.users.set(user.id, user);
    return user;
  }

  async delete(id: string): Promise<void> {
    this.users.delete(id);
  }
}

// 文件：new/services/UserService.ts
// 业务逻辑与存储实现解耦
class UserService {
  constructor(private repository: UserRepositoryInterface) {}

  async getUser(id: string): Promise<User> {
    const user = await this.repository.findById(id);
    if (!user) {
      throw new Error(`User ${id} not found`);
    }
    return user;
  }

  async createUser(name: string, email: string): Promise<User> {
    // 业务验证逻辑
    if (!email.includes('@')) {
      throw new Error('Invalid email');
    }

    const user: User = {
      id: crypto.randomUUID(),
      name,
      email
    };

    return this.repository.save(user);
  }
}

// 使用示例
const repository = new InMemoryUserRepository();
const service = new UserService(repository);

service.createUser('Alice', 'alice@example.com')
  .then(user => console.log('Created:', user))
  .catch(err => console.error('Error:', err));

