  },

  // 环境变量
  "env": {
    "NODE_ENV": "development",
    "PORT": "3000",
    "DATABASE_URL": "postgresql://localhost:5432/mydb"
  },

  // 命令别名 - 常用操作简写
  "aliases": {
    // 开发相关
    "dev": "npm run dev",
    "dev:debug": "NODE_OPTIONS='--inspect' npm run dev",

    // 构建相关
    "build": "npm run build",
    "build:prod": "NODE_ENV=production npm run build",

    // 测试相关
    "test": "npm run test",
    "test:watch": "npm run test -- --watch",
    "test:coverage": "npm run test -- --coverage",

    // 数据库相关
    "db:migrate": "npx prisma migrate dev",
    "db:seed": "npx prisma db seed",
    "db:reset": "npx prisma migrate reset --force",
    "db:studio": "npx prisma studio",

    // Docker 相关
    "docker:up": "docker-compose up -d",
    "docker:down": "docker-compose down",
    "docker:logs": "docker-compose logs -f app",
    "docker:rebuild": "docker-compose up -d --build",

    // Git 相关
    "status": "git status",
    "commit": "git add -A && git commit",
    "push": "git push origin $(git branch --show-current)",
    "pull": "git pull origin $(git branch --show-current)",

    // CI/CD
    "ci": "npm run lint && npm run test && npm run build"
  },

  // 工具配置
  "tools": {
    // Git 配置
    "git": {
      "autoCommit": false,
      "autoPush": false,
      "commitMessageTemplate": "[${type}] ${message}\n\nRefs: ${ticket}",
      "allowedBranches": ["main", "develop", "feature/*", "bugfix/*"]
    },

    // Jest 配置
    "jest": {
      "coverage": true,
      "watchMode": false,
      "testPathPattern": "(src|tests)/**/*.test.{ts,tsx}"
    },

    // Prisma 配置
    "prisma": {
      "autoGenerate": true,
      "validateSchemaOnSave": true
    },

    // TypeScript 配置
    "typescript": {
      "strict": true,
      "autoFix": true
    }
  }
}

// 使用示例
// > dev             -> 启动开发服务器
// > docker:up       -> 启动 Docker 容器
// > db:migrate      -> 运行数据库迁移
// > ci              -> 运行完整的 CI 检查
```

